1	import { useState } from 'react';
2	import { CardList } from '@/shared/components/CardList/CardList';
3	import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
4	import { Input } from '@/shared/components/ui/input';
5	import { Label } from '@/shared/components/ui/label';
6	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
7	import { Badge } from '@/shared/components/ui/badge';
8	import { Button } from '@/shared/components/ui/button';
9	import { emptyToNull } from '@/shared/query/queryHelpers';
10	import { useListPage } from '@/shared/hooks/useListPage';
11	import { ForbiddenDetailDialog } from './ForbiddenDetailDialog';
12	
13	const filtersInitialState = Object.freeze({
14	    phwrdNm: '',
15	    useYn: '',
16	});
17	
18	const ForbiddenCard = ({ forbidden, onClick }) => (
19	    <button
20	        type='button'
21	        onClick={() => onClick(forbidden)}
22	        className='w-full text-left bg-card border border-border rounded-lg p-4 hover:border-primary/20 transition-all'
23	    >
24	        <div className='flex items-start justify-between gap-3'>
25	            <div className='min-w-0 flex-1'>
26	                <div className='mb-1'>
27	                    <span className='text-[15px] font-semibold text-foreground'>
28	                        {forbidden.phwrdNm}
29	                    </span>
30	                </div>
31	                <div className='text-[13px] text-muted-foreground flex items-center gap-4 flex-wrap'>
32	                    {forbidden.enctCycl && <span>제정 {forbidden.enctCycl}차</span>}
33	                    {forbidden.rmrkCn && (
34	                        <span className='truncate max-w-[300px]'>
35	                            {forbidden.rmrkCn}
36	                        </span>
37	                    )}
38	                </div>
39	            </div>
40	            <div className='shrink-0'>
41	                <Badge variant={forbidden.useYn === 'Y' ? 'success' : 'muted'}>
42	                    {forbidden.useYn === 'Y' ? '사용' : '미사용'}
43	                </Badge>
44	            </div>
45	        </div>
46	    </button>
47	);
48	
49	export const ForbiddenListPage = () => {
50	    const [filters, setFilters] = useState(filtersInitialState);
51	    const { request, setRequest, setSelectedId, isDetailOpen, pageQuery, detailQuery } = useListPage({
52	        listQueryKey: 'forbidden-list',
53	        listUrl: '/forbiddens/search',
54	        detailQueryKey: 'forbidden-detail',
55	        detailUrl: '/forbiddens',
56	        initialRequest: { page: 1, size: 20 },
57	    });
58	
59	    return (
60	        <div className='space-y-4'>
61	            <h1 className='text-lg font-bold text-foreground m-0'>
62	                금칙어 목록
63	            </h1>
64	
65	            <SearchForm
66	                onSubmit={() => {
67	                    setRequest({
68	                        page: 1,
69	                        size: request.size,
70	                        phwrdNm: emptyToNull(filters.phwrdNm),
71	                        useYn: emptyToNull(filters.useYn),
72	                    });
73	                }}
74	                onReset={() => {
75	                    setFilters(filtersInitialState);
76	                    setRequest({ page: 1, size: request.size });
77	                }}
78	            >
79	                <div className='grid w-full gap-3 md:grid-cols-2'>
80	                    <div className='space-y-2'>
81	                        <Label htmlFor='phwrdNm'>금칙어명</Label>
82	                        <Input
83	                            id='phwrdNm'
84	                            value={filters.phwrdNm}
85	                            onChange={(event) =>
86	                                setFilters((current) => ({ ...current, phwrdNm: event.target.value }))
87	                            }
88	                        />
89	                    </div>
90	                    <div className='space-y-2'>
91	                        <Label htmlFor='useYn'>사용여부</Label>
92	                        <Select
93	                            value={filters.useYn || 'ALL'}
94	                            onValueChange={(value) =>
95	                                setFilters((current) => ({ ...current, useYn: value === 'ALL' ? '' : value }))
96	                            }
97	                        >
98	                            <SelectTrigger id='useYn' className='bg-background'>
99	                                <SelectValue placeholder="전체" />
100	                            </SelectTrigger>
101	                            <SelectContent>
102	                                <SelectItem value='ALL'>전체</SelectItem>
103	                                <SelectItem value='Y'>사용</SelectItem>
104	                                <SelectItem value='N'>미사용</SelectItem>
105	                            </SelectContent>
106	                        </Select>
107	                    </div>
108	                </div>
109	            </SearchForm>
110	
111	            <CardList
112	                pageData={pageQuery.data ?? null}
113	                pageSizeOptions={[10, 20, 50, 100]}
114	                onPageChange={({ page, size }) => setRequest((current) => ({ ...current, page, size }))}
115	                renderItem={(forbidden) => (
116	                    <ForbiddenCard
117	                        key={forbidden.id}
118	                        forbidden={forbidden}
119	                        onClick={(f) => setSelectedId(f.id)}
120	                    />
121	                )}
122	            />
123	
124	            <ForbiddenDetailDialog
125	                forbidden={detailQuery.data ?? null}
126	                open={isDetailOpen}
127	                onOpenChange={(open) => {
128	                    if (!open) setSelectedId(null);
129	                }}
130	            />
131	        </div>
132	    );
133	};
134

